import React, { useState } from "react";
import Topbar from "./Topbar";
import { Sidebar, MobileBanner } from "./Sidebar";
import StepIndicator from "./StepIndicator";
import ApiStatusBanner from "./ApiStatusBanner";
import Step1PersonalDetails from "./Step1PersonalDetails";
import Step2Security from "./Step2Security";
import Step3OTP from "./Step3OTP";
import SuccessScreen from "./SuccessScreen";

import { useRegistrationForm, useOtp } from "../hooks/useRegistrationForm";
import { validateName, validateEmail, validateMobile, validatePassword, validateConfirmPassword } from "../utils/validators";
import { checkEmailAvailability, sendOtp, verifyOtp, registerUser, googleAuth } from "../utils/api";

const STEP_LABELS = [
  "Step 1 of 3 — Personal details",
  "Step 2 of 3 — Security & consent",
  "Step 3 of 3 — Verify your identity",
];

export default function RegistrationPage() {
  const { step, totalSteps, fields, errors, updateField, setMultipleErrors, nextStep, prevStep } = useRegistrationForm();
  const { generatedOtp, setGeneratedOtp, timerSeconds, timerActive, startTimer } = useOtp();

  const [apiStatus, setApiStatus] = useState({ type: null, message: "" });
  const [loading, setLoading]     = useState(false);
  const [otpDigits, setOtpDigits] = useState(Array(6).fill(""));
  const [otpError, setOtpError]   = useState("");
  const [registered, setRegistered] = useState(false);
  const [userId, setUserId]       = useState("");

  function showStatus(type, message, autoClear = true) {
    setApiStatus({ type, message });
    if (autoClear && type !== "loading")
      setTimeout(() => setApiStatus({ type: null, message: "" }), 3500);
  }

  async function handleStep1Continue() {
    const errs = {};
    const fn = validateName(fields.firstName, "First name");
    const ln = validateName(fields.lastName, "Last name");
    const em = validateEmail(fields.email);
    const mo = validateMobile(fields.mobile);
    if (!fn.valid) errs.firstName = fn.message;
    if (!ln.valid) errs.lastName  = ln.message;
    if (!em.valid) errs.email     = em.message;
    if (!mo.valid) errs.mobile    = mo.message;
    if (Object.keys(errs).length) { setMultipleErrors(errs); return; }

    setLoading(true);
    showStatus("loading", "Checking email availability…", false);
    try {
      const res = await checkEmailAvailability(fields.email);
      if (!res.available) { showStatus("error", res.message); setMultipleErrors({ email: res.message }); }
      else { showStatus("success", "✓ Email is available"); nextStep(); }
    } catch (e) { showStatus("error", e.message || "Failed to verify email."); }
    finally { setLoading(false); }
  }

  async function handleStep2Continue() {
    const errs = {};
    const pw = validatePassword(fields.password);
    const cp = validateConfirmPassword(fields.password, fields.confirmPassword);
    if (!pw.valid) errs.password        = pw.message;
    if (!cp.valid) errs.confirmPassword = cp.message;
    if (!fields.termsAccepted) errs.termsAccepted = "You must accept the Terms of Service.";
    if (Object.keys(errs).length) { setMultipleErrors(errs); return; }

    setLoading(true);
    showStatus("loading", "Sending OTP to your mobile…", false);
    try {
      const res = await sendOtp(fields.mobile, fields.countryCode);
      if (res.success) { setGeneratedOtp(res.otp || ""); showStatus("success", "✓ OTP sent!"); nextStep(); startTimer(30); }
      else showStatus("error", "Failed to send OTP. Please try again.");
    } catch (e) { showStatus("error", e.message || "Failed to send OTP."); }
    finally { setLoading(false); }
  }

  async function handleResendOtp() {
    setLoading(true);
    showStatus("loading", "Resending OTP…", false);
    try {
      const res = await sendOtp(fields.mobile, fields.countryCode);
      setGeneratedOtp(res.otp || "");
      showStatus("success", "✓ New OTP sent!");
      startTimer(30);
      setOtpDigits(Array(6).fill(""));
      setOtpError("");
    } catch (e) { showStatus("error", "Failed to resend OTP."); }
    finally { setLoading(false); }
  }

  async function handleVerifyAndRegister() {
    const entered = otpDigits.join("");
    if (entered.length < 6) { setOtpError("Please enter the complete 6-digit OTP."); return; }
    setOtpError("");
    setLoading(true);
    showStatus("loading", "Verifying OTP…", false);
    try {
      const vRes = await verifyOtp(fields.mobile, entered, generatedOtp);
      if (!vRes.valid) { showStatus("error", vRes.message); setOtpError(vRes.message); setLoading(false); return; }
      showStatus("loading", "Creating your account…", false);
      const rRes = await registerUser({ firstName: fields.firstName, lastName: fields.lastName, email: fields.email, mobile: fields.mobile, countryCode: fields.countryCode, dob: fields.dob, gender: fields.gender, referral: fields.referral });
      if (rRes.success) { setUserId(rRes.userId); showStatus("success", "Account created!"); setTimeout(() => setRegistered(true), 400); }
      else showStatus("error", rRes.message || "Registration failed.");
    } catch (e) { showStatus("error", e.message || "Something went wrong. Please try again."); }
    finally { setLoading(false); }
  }

  async function handleGoogle() {
    setLoading(true);
    showStatus("loading", "Connecting to Google…", false);
    try {
      const res = await googleAuth();
      if (res.success) { showStatus("success", "✓ Google account connected!"); alert("Google auth successful (demo)."); }
    } catch (e) { showStatus("error", e.message || "Google auth failed."); }
    finally { setLoading(false); }
  }

  return (
    <div className="reg-page">
      <Topbar />
      <MobileBanner />

      <main className="reg-layout">
        <Sidebar />

        <div className="reg-card">
          {registered ? (
            <SuccessScreen firstName={fields.firstName} userId={userId} />
          ) : (
            <>
              <StepIndicator current={step} total={totalSteps} />
              <h1 style={{ fontSize: "18px", fontWeight: 600, color: "var(--text-primary)", marginBottom: "4px" }}>
                Create your account
              </h1>
              <p style={{ fontSize: "13px", color: "var(--text-muted)", marginBottom: "22px" }}>
                {STEP_LABELS[step - 1]}
              </p>

              <ApiStatusBanner type={apiStatus.type} message={apiStatus.message} />

              {step === 1 && <Step1PersonalDetails fields={fields} errors={errors} updateField={updateField} onContinue={handleStep1Continue} loading={loading} />}
              {step === 2 && <Step2Security fields={fields} errors={errors} updateField={updateField} onContinue={handleStep2Continue} onBack={prevStep} onGoogle={handleGoogle} loading={loading} />}
              {step === 3 && <Step3OTP mobile={fields.mobile} countryCode={fields.countryCode} otpValue={otpDigits} onOtpChange={setOtpDigits} timerSeconds={timerSeconds} timerActive={timerActive} onVerify={handleVerifyAndRegister} onResend={handleResendOtp} onBack={prevStep} loading={loading} error={otpError} />}

              <div style={{ textAlign: "center", marginTop: "16px", fontSize: "13px", color: "var(--text-muted)" }}>
                Already have an account? <a href="#login">Log in</a>
              </div>
            </>
          )}
        </div>
      </main>
    </div>
  );
}
